 21→        match std::env::var("SHATTER_LOG_LEVEL")
 22→            .unwrap_or_default()
 23→            .to_lowercase()
 24→            .as_str()
 25→        {
 26→            "error" => FrontendLogLevel::Error,
 27→            "warn" => FrontendLogLevel::Warn,
 28→            "debug" => FrontendLogLevel::Debug,
